{
  "domain_analysis": {
    "business_context": "A courier-tracking feature is being specified where customers would see their courier's real-time location during delivery. Two internal stakeholder teams have issued directly contradictory requirements: Customer Success demands full GPS transparency as a competitive differentiator, while Operations demands no location sharing due to driver retention losses from perceived surveillance.",
    "bounded_context": "Delivery Tracking / Last-Mile Visibility",
    "ubiquitous_language": [
      { "term": "Courier", "definition": "The delivery driver transporting a parcel from depot/pickup to the customer's delivery address" },
      { "term": "Real-time location", "definition": "The courier's GPS coordinates updated at frequent intervals during an active delivery" },
      { "term": "Active delivery", "definition": "The period from when a courier departs for a delivery until the parcel is handed off or marked delivered" },
      { "term": "Location sharing", "definition": "The act of exposing any form of courier positional data to the end customer" },
      { "term": "ETA", "definition": "Estimated Time of Arrival — a derived value indicating when the courier is expected to reach the delivery address, which can be computed from location without exposing location" }
    ]
  },

  "business_rules": [],

  "acceptance_criteria": [],

  "edge_cases": [
    { "scenario": "Courier is stationary for extended period (e.g., traffic, break) and customer sees no movement", "expected_behavior": "Depends on resolution — if location is shared, stalled couriers will generate support tickets and customer anxiety; if ETA-only, the system absorbs this gracefully" },
    { "scenario": "Courier takes a detour (multi-drop route) that moves them away from the customer", "expected_behavior": "Exact GPS would show the courier moving away, causing confusion and complaints. An abstracted view (ETA or zone) would not expose this" },
    { "scenario": "Courier is at a sensitive personal location before starting delivery", "expected_behavior": "If tracking begins before active delivery, personal location data is leaked — a privacy and potentially legal issue" },
    { "scenario": "Customer uses location data to intercept courier en route", "expected_behavior": "Safety concern for couriers — exact coordinates enable physical interception, which is one root cause of driver discomfort" }
  ],

  "business_impact": {
    "financial": "Driver churn is extremely expensive — recruiting, onboarding, and training a replacement courier costs significantly more than retaining one. If Operations is correct that location sharing drives attrition, the feature as specified by Customer Success could increase costs substantially. Conversely, Customer Success argues transparency drives customer acquisition/retention, which is revenue-positive. These must be quantified before a decision is made.",
    "operational": "Losing experienced couriers degrades delivery quality, increases failed deliveries, and overloads remaining drivers. A depleted driver pool is an existential operational risk for a courier business. Customer-facing tracking, if poorly scoped, also increases support volume (customers calling about perceived anomalies in courier movement).",
    "user": "Customers want delivery predictability — they want to know WHEN their package arrives so they can be available. Whether they need exact GPS vs. a reliable ETA is an assumption that has not been validated. Couriers are also users of this system; their experience and sense of safety directly affects service quality.",
    "risk": "GDPR and local privacy regulations may constrain sharing of worker location data with third parties (customers). Sharing exact GPS coordinates without driver consent may create legal liability. Driver safety risk from location-based interception is non-trivial in certain markets.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Want delivery predictability. Exact GPS is one way to provide it, but not the only way. Over-sharing can actually degrade experience (confusion from detours, stalled locations)." },
      { "group": "Couriers/Drivers", "impact": "Directly affected. Feel surveilled, which impacts job satisfaction, retention, and potentially safety. Their cooperation is essential — without drivers, there is no service." },
      { "group": "Customer Success team", "impact": "Owns customer satisfaction metrics. Believes transparency is a differentiator but may be conflating 'transparency' with 'exact GPS coordinates.'" },
      { "group": "Operations team", "impact": "Owns driver retention and fleet capacity. Has concrete evidence of driver attrition linked to location sharing." },
      { "group": "Legal/Compliance", "impact": "NOT YET CONSULTED. Must weigh in on privacy regulations governing real-time worker location sharing with customers." },
      { "group": "Executive leadership", "impact": "Must arbitrate this conflict. This is a strategic decision about which side of the marketplace (supply vs. demand) to prioritize, with significant business model implications." }
    ]
  },

  "confidence": {
    "level": 20,
    "reasoning": "Confidence is critically low because the two authoritative stakeholder teams have issued mutually exclusive requirements, both framed as non-negotiable. It is impossible to produce correct acceptance criteria when the definition of 'correct' is contradicted by equally-weighted business authorities. Additionally, Legal/Compliance has not been consulted on what may be a regulated area (worker location privacy). No customer research has been cited to validate that exact GPS (vs. ETA or zone-based tracking) is what customers actually need.",
    "high_confidence_areas": [
      "The conflict is real and must be resolved at the executive level before engineering begins",
      "Driver retention is a supply-side business risk that cannot be dismissed",
      "Customer predictability is a legitimate need but 'exact GPS' is one of several solutions",
      "Privacy/legal review is mandatory before any location-sharing feature ships"
    ],
    "low_confidence_areas": [
      "What 'transparency' actually means to customers — no user research cited",
      "Whether driver attrition is caused by location sharing specifically or by broader working conditions",
      "Regulatory constraints in the markets where this feature would launch",
      "Whether a compromise solution (e.g., ETA-only, zone-based) would satisfy either or both teams"
    ],
    "assumptions": [
      "Both teams have legitimate business reasons behind their positions",
      "Neither team has unilateral authority to override the other",
      "No prior executive decision exists that resolves this conflict",
      "The company operates in jurisdictions where worker location privacy may be regulated"
    ]
  },

  "escalations": [
    {
      "type": "contradiction",
      "description": "Customer Success requires exact GPS location sharing with customers as non-negotiable. Operations requires zero location sharing with customers as non-negotiable. These requirements are mutually exclusive. One team's 'correct' is the other team's 'violation.' This cannot be resolved at the engineering or domain level — it is a strategic business decision about marketplace priority (supply-side driver experience vs. demand-side customer experience).",
      "affected_stakeholders": ["Customers", "Couriers", "Customer Success", "Operations", "Legal", "Executive Leadership"],
      "options": [
        "A: Full GPS sharing (Customer Success wins) — risk: accelerated driver attrition, potential legal exposure",
        "B: No location sharing (Operations wins) — risk: competitive disadvantage if competitors offer tracking",
        "C: Compromise — ETA-based or zone-based tracking that gives customers predictability without exposing exact courier location. Requires both teams to move off their 'non-negotiable' positions.",
        "D: Driver-consent model — couriers opt in/out of location sharing, with incentives for participation. Respects driver autonomy but creates inconsistent customer experience."
      ],
      "recommendation": "Option C (ETA/zone-based tracking) is the industry-standard approach used by major logistics providers for exactly this reason. It resolves the customer need (delivery predictability) without creating the driver surveillance problem. However, I CANNOT set this as acceptance criteria because both teams have framed their positions as non-negotiable. Executive arbitration is required. Additionally, Legal/Compliance MUST review any option before it proceeds."
    },
    {
      "type": "missing_context",
      "description": "Legal/Compliance has not been consulted. In many jurisdictions (EU/GDPR, California/CCPA, and others), sharing real-time worker location data with third parties has specific regulatory requirements including explicit consent, data minimization, and purpose limitation. Any decision made without legal review could expose the company to regulatory action.",
      "affected_stakeholders": ["Legal", "Couriers", "Executive Leadership"],
      "options": [
        "Engage Legal/Compliance immediately to define the regulatory envelope before any product decision",
        "Proceed without legal review (NOT RECOMMENDED)"
      ],
      "recommendation": "Legal review is mandatory and should happen in parallel with the executive arbitration of the stakeholder conflict."
    }
  ],

  "rejection_reasons": [
    { "violation": "Cannot implement 'show exact GPS at all times' while simultaneously implementing 'never show location' — the requirements are logically contradictory", "business_rule_broken": "No coherent business rule can be defined when two authoritative stakeholders demand opposite behaviors" },
    { "violation": "Proceeding with either requirement unilaterally would violate the other team's stated business constraint", "business_rule_broken": "Engineering cannot and should not arbitrate strategic business conflicts — this requires executive decision authority" }
  ]
}

